  ds_onhireOrder.setCellData(onRow, "odrDelYn", scwin.YN_NO);
  ds_onhireOrder.setCellData(onRow, "wrkPatternCd", "00");
  ds_onhireOrder.setCellData(onRow, "chClsCd", "0");
